#!/usr/bin/bash

jq -nr '["id", "scheduled", "attendance", "entry_mode", "clock", "quarter", "game_type", "conference_game", "duration","weather_cond", "weather_hum", "weather_temp", "wind_speed", "wind_dir","season_year", "season_type", "season_name", "week", "venue_name", "venue_state", "venue_state_dup", "surface", "roof","home_name", "home_market", "home_alias", "home_timeouts_used", "home_timeouts_rem", "home_points", "home_challenges_used", "home_challenges_rem", "home_wins", "home_losses", "home_ties","away_name", "away_market", "away_alias", "away_timeouts_used", "away_timeouts_rem", "away_points", "away_challenges_used", "away_challenges_rem", "away_wins", "away_losses", "away_ties","h_poss_time", "h_avg_gain", "h_safeties", "h_turnovers", "h_play_count", "h_rush_plays", "h_total_yards", "h_fumbles", "h_lost_fumbles", "h_penalties", "h_penalty_yards", "h_return_yards","a_poss_time", "a_avg_gain", "a_safeties", "a_turnovers", "a_play_count", "a_rush_plays", "a_total_yards", "a_fumbles", "a_lost_fumbles", "a_penalties", "a_penalty_yards", "a_return_yards"] | @csv' > 2021-2025_games.csv

